class Solution {
    public int addMinimum(String word) {
        int aCount = 0;
        int bCount = 0;
        int cCount = 0;
        for (char ch : word.toCharArray()) {
            if (ch == 'a') {
                aCount++;
            } else if (ch == 'b') {
                bCount++;
            } else {
                cCount++;
            }
        }
        return Math.max(aCount, Math.max(bCount, cCount)) * 2 - Math.min(aCount, Math.min(bCount, cCount));
    }
}
```
